#!/usr/bin/env node
// Embeds the platform-specific better_sqlite3.node binary as base64 into
// src/native-bundle.js so @yao-pkg/pkg can bundle it via src/**/*.js.
// pkg.assets globs are broken for node20 targets, so native .node files are
// handled the same way as other assets — embedded in JS then extracted at
// runtime by src/native-loader.js.
//
// This file is generated at build time (after release:check) and is NOT
// committed to the repo (see .gitignore). Each platform produces its own
// platform-specific native-bundle.js.
//
// Run: node scripts/generate-native-bundle.js

'use strict';

const fs   = require('fs');
const path = require('path');
const crypto = require('crypto');

const ROOT      = path.resolve(__dirname, '..');
const NODE_FILE = path.join(ROOT, 'node_modules', 'better-sqlite3', 'build', 'Release', 'better_sqlite3.node');
const OUTPUT    = path.join(ROOT, 'src', 'native-bundle.js');

if (!fs.existsSync(NODE_FILE)) {
  console.error('ERROR: better_sqlite3.node not found — run npm install (or npm rebuild better-sqlite3) first');
  process.exit(1);
}

// When build-exe.js cross-compiles for a different Node ABI, it sets
// PAPERWEIGHT_BUNDLE_ABI to the target ABI so the bundle metadata is correct.
// Without it, we assume the binary was built for the running Node version.
const bundleAbi = process.env.PAPERWEIGHT_BUNDLE_ABI || process.versions.modules;

const b64  = fs.readFileSync(NODE_FILE).toString('base64');
const hash = crypto.createHash('sha256').update(fs.readFileSync(NODE_FILE)).digest('hex');
const size = (fs.statSync(NODE_FILE).size / 1024).toFixed(0);

const content = [
  '// AUTO-GENERATED by scripts/generate-native-bundle.js — do not edit by hand.',
  '// Platform-specific better_sqlite3 native binary, embedded as base64.',
  '// NOT committed to the repo (gitignored). Regenerated on each platform build.',
  '',
  '\'use strict\';',
  '',
  'module.exports = {',
  `  data: Buffer.from(${JSON.stringify(b64)}, 'base64'),`,
  `  sha256: ${JSON.stringify(hash)},`,
  `  platform: ${JSON.stringify(process.platform)},`,
  `  arch: ${JSON.stringify(process.arch)},`,
  `  abi: ${JSON.stringify(bundleAbi)},`,
  '};',
  '',
].join('\n');

fs.writeFileSync(OUTPUT, content, 'utf8');
console.log(`Generated ${OUTPUT} (${size} KB ${process.platform}/${process.arch} native binary).`);
